(function(){'use strict';function initSmoothScroll(){document.querySelectorAll('a[href^="#"]').forEach(function(anchor){anchor.addEventListener('click',function(e){var href=this.getAttribute('href');if(href==='#')return;var target=document.querySelector(href);if(target){e.preventDefault();target.scrollIntoView({behavior:'smooth',block:'start'});}});});}function initMobileNav(){var navToggle=document.querySelector('.nav-toggle');var navMenu=document.querySelector('.nav-menu');if(!navToggle||!navMenu)return;navToggle.addEventListener('click',function(){var isExpanded=navToggle.getAttribute('aria-expanded')==='true';navToggle.setAttribute('aria-expanded',!isExpanded);navMenu.classList.toggle('active');});document.querySelectorAll('.nav-link').forEach(function(link){link.addEventListener('click',function(){navToggle.setAttribute('aria-expanded','false');navMenu.classList.remove('active');});});document.addEventListener('keydown',function(e){if(e.key==='Escape'){navToggle.setAttribute('aria-expanded','false');navMenu.classList.remove('active');}});document.addEventListener('click',function(e){if(!e.target.closest('.nav')&&navMenu.classList.contains('active')){navToggle.setAttribute('aria-expanded','false');navMenu.classList.remove('active');}});}function debounce(fn,wait){var timeout;return function(){var args=arguments;var later=function(){timeout=null;fn.apply(null,args);};clearTimeout(timeout);timeout=setTimeout(later,wait);};}function initScrollAnimations(){var animateElements=document.querySelectorAll('.animate-on-scroll');if(animateElements.length===0)return; if('IntersectionObserver' in window){try{var observerOptions={threshold:.1,rootMargin:'0px 0px -50px 0px'};var observer=new IntersectionObserver(function(entries){entries.forEach(function(entry){if(entry.isIntersecting){entry.target.classList.add('animated');observer.unobserve(entry.target);}});},observerOptions);animateElements.forEach(function(element){observer.observe(element);});}catch(err){console.error('Animation observer failed:',err);animateElements.forEach(function(el){el.classList.add('animated');});}}else{animateElements.forEach(function(el){el.classList.add('animated');});}}function initActiveNav(){var navLinks=document.querySelectorAll('.nav-link[href^="#"]');if(navLinks.length===0)return;function updateActiveLink(){var current='';navLinks.forEach(function(link){var href=link.getAttribute('href');if(href==='#'||href==='')return;var section=document.querySelector(href);if(section){var rect=section.getBoundingClientRect();if(rect.top<=100){current=href;}}});navLinks.forEach(function(link){link.classList.remove('active');if(link.getAttribute('href')===current){link.classList.add('active');}});}var handler=debounce(function(){window.requestAnimationFrame(updateActiveLink);},50);try{window.addEventListener('scroll',handler,{passive:true});}catch(e){window.addEventListener('scroll',handler);}updateActiveLink();}function initScrollToTop(){var scrollButton=document.getElementById('scroll-to-top');if(!scrollButton)return;var handler=debounce(function(){window.requestAnimationFrame(function(){if(window.scrollY>300){scrollButton.classList.add('visible');}else{scrollButton.classList.remove('visible');}});},50);try{window.addEventListener('scroll',handler,{passive:true});}catch(e){window.addEventListener('scroll',handler);}scrollButton.addEventListener('click',function(e){e.preventDefault();window.scrollTo({top:0,behavior:'smooth'});});}function initFAQAccordion(){var faqQuestions=document.querySelectorAll('.faq-question');if(faqQuestions.length===0)return;faqQuestions.forEach(function(question){var faqItem=question.closest('.faq-item');var toggle=question.querySelector('.faq-toggle');if(faqItem&&toggle){var isActive=faqItem.classList.contains('active');toggle.setAttribute('aria-expanded',isActive);question.addEventListener('click',function(e){e.stopPropagation();faqItem.classList.toggle('active');var newState=faqItem.classList.contains('active');toggle.setAttribute('aria-expanded',newState);});}});}function initReadingProgressBar(){var progressBar=document.getElementById('reading-progress');if(!progressBar)return;var handler=debounce(function(){window.requestAnimationFrame(function(){try{var docHeight=document.documentElement.scrollHeight-window.innerHeight;var scrolled=docHeight>0?window.scrollY/docHeight*100:0;progressBar.style.width=scrolled+'%';}catch(err){console.error('Reading progress update failed:',err);}});},50);try{window.addEventListener('scroll',handler,{passive:true});}catch(e){window.addEventListener('scroll',handler);} }function initTableOfContents(){try{var tocContainer=document.getElementById('table-of-contents');var article=document.querySelector('article');if(!tocContainer||!article)return;var headings=Array.from(article.querySelectorAll('h2'));if(headings.length===0)return;var tocList=document.createElement('ul');headings.forEach(function(heading,index){if(!heading.id){heading.id='heading-'+index;}var li=document.createElement('li');var a=document.createElement('a');a.href='#'+heading.id;a.textContent=heading.textContent;a.classList.add('toc-link');li.appendChild(a);tocList.appendChild(li);});tocContainer.appendChild(tocList);var handler=debounce(function(){window.requestAnimationFrame(function(){var current='';headings.forEach(function(heading){var rect=heading.getBoundingClientRect();if(rect.top<=150){current=heading.id;}});document.querySelectorAll('.toc-link').forEach(function(link){link.classList.remove('active');if(link.getAttribute('href')==='#'+current){link.classList.add('active');}});});},50);try{window.addEventListener('scroll',handler,{passive:true});}catch(e){window.addEventListener('scroll',handler);} }catch(err){console.error('TOC generation failed:',err);} }function updateFooterYear(){var yearElement=document.getElementById('year');if(yearElement){yearElement.textContent=new Date().getFullYear();}}function initCopyCodeButton(){document.querySelectorAll('.code-block').forEach(function(block){if(block.querySelector('.code-block-copy'))return;var copyButton=document.createElement('button');copyButton.className='code-block-copy';copyButton.setAttribute('aria-label','Copy code to clipboard');copyButton.setAttribute('type','button');copyButton.textContent='Copy';if(!navigator.clipboard){copyButton.setAttribute('disabled','true');copyButton.title='Copy not supported in this browser';}block.appendChild(copyButton);copyButton.addEventListener('click',function(e){e.preventDefault();var code=(block.querySelector('code')&&block.querySelector('code').textContent)||block.textContent;var uiStatus=document.getElementById('ui-status');if(!uiStatus){uiStatus=document.createElement('div');uiStatus.id='ui-status';uiStatus.setAttribute('aria-live','polite');uiStatus.style.position='absolute';uiStatus.style.left='-9999px';uiStatus.style.width='1px';uiStatus.style.height='1px';uiStatus.style.overflow='hidden';document.body.appendChild(uiStatus);}function announce(text){uiStatus.textContent='';setTimeout(function(){uiStatus.textContent=text;},50);}if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(code).then(function(){copyButton.textContent='Copied!';copyButton.classList.add('copied');announce('Code copied to clipboard');setTimeout(function(){copyButton.textContent='Copy';copyButton.classList.remove('copied');},2000);}).catch(function(err){console.error('Failed to copy with Clipboard API:',err);copyButton.textContent='Error';announce('Copy failed');setTimeout(function(){copyButton.textContent='Copy';},1500);});return;}try{var textarea=document.createElement('textarea');textarea.value=code;textarea.style.position='fixed';textarea.style.left='-9999px';document.body.appendChild(textarea);textarea.select();var successful=document.execCommand('copy');document.body.removeChild(textarea);if(successful){copyButton.textContent='Copied!';copyButton.classList.add('copied');announce('Code copied to clipboard');setTimeout(function(){copyButton.textContent='Copy';copyButton.classList.remove('copied');},2000);}else{copyButton.textContent='Error';announce('Copy not supported');setTimeout(function(){copyButton.textContent='Copy';},1500);} }catch(err){console.error('Copy fallback failed:',err);copyButton.textContent='Not supported';announce('Copy not supported');setTimeout(function(){copyButton.textContent='Copy';},1500);} });});}function initBlogFilter(){var buttons=document.querySelectorAll('.filter-btn');var grid=document.getElementById('blog-grid');if(!buttons.length||!grid)return;var cards=Array.from(grid.querySelectorAll('.blog-card'));var emptyState=document.getElementById('blog-empty-state');function applyFilter(filter){var visible=0;cards.forEach(function(card){var cat=card.dataset.category||'';if(filter==='all'||cat===filter){card.style.display='';visible++;}else{card.style.display='none';}});if(emptyState){emptyState.style.display=visible===0?'':'none';}};buttons.forEach(function(btn){btn.addEventListener('click',function(){buttons.forEach(function(b){b.classList.remove('active');b.setAttribute('aria-pressed','false');});btn.classList.add('active');btn.setAttribute('aria-pressed','true');applyFilter(btn.dataset.filter);});});var initial=document.querySelector('.filter-btn.active');applyFilter(initial?initial.dataset.filter:'all');}function initAll(){try{updateFooterYear();initSmoothScroll();initMobileNav();initScrollAnimations();initActiveNav();initScrollToTop();initFAQAccordion();initReadingProgressBar();initTableOfContents();initCopyCodeButton();initBlogFilter();}catch(err){console.error('Initialization error in initAll:',err);}}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initAll);}else{initAll();}})();